<?php
namespace App\Http\Controllers\Tenant;use App\Http\Controllers\Controller;use App\Models\{Task,TaskAttachment};use App\Support\CurrentWorkspace;use Illuminate\Http\Request;use App\Services\Billing\PlanLimitService;use Illuminate\Support\Facades\Storage;use Illuminate\Validation\Rule;
class TaskAttachmentController extends Controller{use Concerns;public function store(Request $r,Task $task,CurrentWorkspace $cw,PlanLimitService $limits){$this->requirePerm('tenant.tasks.update');$w=$this->ws($cw);$max=(int)config('workproof.tasks.max_attachment_kb',10240);$d=$r->validate(['attachment'=>'required|file|mimes:jpg,jpeg,png,pdf,doc,docx,xls,xlsx,txt|max:'.$max,'attachment_type'=>['nullable',Rule::in(['general','reference','proof_candidate'])]]);$file=$d['attachment'];if(!$limits->canUseStorage($w,$file->getSize()))return back()->withErrors(['plan'=>'Storage limit reached. Please upgrade your plan.']);$path=$file->store("workspaces/{$w->id}/tasks/{$task->id}/attachments",'local');$att=$task->attachments()->create(['workspace_id'=>$w->id,'uploaded_by'=>$r->user()->id,'file_name'=>basename($path),'original_name'=>$file->getClientOriginalName(),'file_path'=>$path,'file_disk'=>'local','mime_type'=>$file->getMimeType(),'file_size'=>$file->getSize(),'attachment_type'=>$d['attachment_type']??'general']);$this->logTask($task,'attachment_uploaded',[],['attachment_id'=>$att->id],'Attachment uploaded');return back()->with('status','Attachment uploaded.');}public function destroy(Task $task,TaskAttachment $attachment){$this->requirePerm('tenant.tasks.update');abort_unless($attachment->task_id===$task->id,404);Storage::disk($attachment->file_disk)->delete($attachment->file_path);$attachment->delete();$this->logTask($task,'attachment_deleted',['attachment_id'=>$attachment->id],[]);return back();}}
